type Cell = [number, number];

function key(x: number, y: number): string {
  return `${x},${y}`;
}

function parseKey(k: string): Cell {
  const [x, y] = k.split(",").map(Number);
  return [x, y];
}

export function nextGeneration(cells: Cell[]): Cell[] {
  const liveSet = new Set<string>();
  for (const [x, y] of cells) {
    liveSet.add(key(x, y));
  }

  const neighborCounts = new Map<string, number>();

  for (const [x, y] of cells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        const nKey = key(x + dx, y + dy);
        neighborCounts.set(nKey, (neighborCounts.get(nKey) ?? 0) + 1);
      }
    }
  }

  const result: Cell[] = [];

  for (const [k, count] of neighborCounts) {
    const isAlive = liveSet.has(k);
    if (isAlive && (count === 2 || count === 3)) {
      result.push(parseKey(k));
    } else if (!isAlive && count === 3) {
      result.push(parseKey(k));
    }
  }

  for (const [x, y] of cells) {
    const k = key(x, y);
    if (!neighborCounts.has(k)) {
      // live cell with 0 neighbors — dies, do nothing
    }
  }

  return result;
}

